package lifecycle

import (
	"os"
	"strconv"
	"time"

	"golang.org/x/sys/unix"
)

// runHelper executes a helper-subprocess mode selected by the ANANKE_HELPER env
// var. Each mode exercises a slice of the lifecycle backend in a real process
// so the parent test can observe process-group behavior directly.
func runHelper(mode string) {
	switch mode {
	case "groupleader":
		helperGroupLeader()
	case "worker":
		helperWorker()
	case "resistant":
		helperResistant()
	case "groupeval":
		helperGroupEval()
	case "group_with_worker":
		helperGroupWithWorker()
	default:
		os.Exit(2)
	}
}

// helperGroupLeader becomes a process-group leader and reports {pid, pgid}.
func helperGroupLeader() {
	b := NewDarwinBackend()
	pgid, err := b.BecomeGroupLeader()
	writeResultFile(os.Getenv(resultEnv), map[string]any{
		"pid":  os.Getpid(),
		"pgid": pgid,
		"err":  errString(err),
	})
}

// helperWorker reports {pid, pgid} then sleeps and exits with a configured code.
// Env: ANANKE_SLEEP_MS (default 2000), ANANKE_EXIT (default 0).
func helperWorker() {
	writeResultFile(os.Getenv(resultEnv), map[string]any{
		"pid":  os.Getpid(),
		"pgid": pgidOf(0),
	})
	sleep := envInt("ANANKE_SLEEP_MS", 2000)
	if sleep > 0 {
		time.Sleep(time.Duration(sleep) * time.Millisecond)
	}
	os.Exit(envInt("ANANKE_EXIT", 0))
}

// helperResistant ignores SIGTERM and sleeps until SIGKILL. Reports {pid, pgid}.
func helperResistant() {
	// Ignore SIGTERM; only SIGKILL can stop us.
	ch := make(chan os.Signal, 1)
	signalNotify(ch, unix.SIGTERM)
	go func() {
		for range ch {
			// swallow
		}
	}()
	writeResultFile(os.Getenv(resultEnv), map[string]any{
		"pid":  os.Getpid(),
		"pgid": pgidOf(0),
	})
	time.Sleep(5 * time.Minute)
	os.Exit(0)
}

// helperGroupEval becomes group leader, launches a worker, and reports both the
// supervisor and worker pid/pgid so the parent can confirm the worker
// inherited the supervisor's group.
func helperGroupEval() {
	b := NewDarwinBackend()
	pgid, err := b.BecomeGroupLeader()
	if err != nil {
		writeResultFile(os.Getenv(resultEnv), map[string]any{"err": errString(err)})
		os.Exit(1)
	}
	env := append(os.Environ(), helperEnv+"=worker", "ANANKE_SLEEP_MS=2000", "ANANKE_EXIT=0")
	wp, err := b.LaunchWorker(os.Args[0], nil, env)
	if err != nil {
		writeResultFile(os.Getenv(resultEnv), map[string]any{"err": errString(err)})
		os.Exit(1)
	}
	workerPgid := pgidOf(wp)
	writeResultFile(os.Getenv(resultEnv), map[string]any{
		"supervisor_pid":  os.Getpid(),
		"supervisor_pgid": pgid,
		"worker_pid":      wp,
		"worker_pgid":     workerPgid,
	})
	// Wait for the worker to exit and reap it so we don't leak a zombie.
	ch, _ := b.WorkerExited(wp)
	<-ch
	_, _ = b.ReapWorker(wp)
}

// helperGroupWithWorker becomes group leader, launches a long-sleep worker, and
// stays alive (sleeping) so the parent can enumerate group members. Reports
// {supervisor_pid, supervisor_pgid, worker_pid}.
func helperGroupWithWorker() {
	b := NewDarwinBackend()
	pgid, err := b.BecomeGroupLeader()
	if err != nil {
		writeResultFile(os.Getenv(resultEnv), map[string]any{"err": errString(err)})
		os.Exit(1)
	}
	env := append(os.Environ(), helperEnv+"=worker", "ANANKE_SLEEP_MS=60000", "ANANKE_EXIT=0")
	wp, err := b.LaunchWorker(os.Args[0], nil, env)
	if err != nil {
		writeResultFile(os.Getenv(resultEnv), map[string]any{"err": errString(err)})
		os.Exit(1)
	}
	writeResultFile(os.Getenv(resultEnv), map[string]any{
		"supervisor_pid":  os.Getpid(),
		"supervisor_pgid": pgid,
		"worker_pid":      wp,
	})
	// Stay alive so the group persists. The parent SIGKILLs us during cleanup.
	time.Sleep(60 * time.Second)
}

func errString(err error) string {
	if err == nil {
		return ""
	}
	return err.Error()
}

func envInt(key string, def int) int {
	if v := os.Getenv(key); v != "" {
		if n, err := strconv.Atoi(v); err == nil {
			return n
		}
	}
	return def
}

func pgidOf(pid int) int {
	g, err := unix.Getpgid(pid)
	if err != nil {
		return 0
	}
	return g
}

