package store

import (
	"context"
	"database/sql"
	"errors"
	"fmt"
	"time"
)

// ErrOutboxNotFound is returned when no outbox row exists for a run, or when an
// acknowledge targets a row that is not pending.
var ErrOutboxNotFound = errors.New("outbox row not found or not pending")

// OutboxRow is a finalization outbox entry (ADR-0003 §2). A row is created in
// the same transaction as a terminal state commit and remains until the
// supervisor confirms finalization.
type OutboxRow struct {
	RunID          string
	TerminalState  State
	SupervisorPID  int
	SupervisorPGID int
	SocketPath     string
	Token          string
	Acknowledged   int // 0 pending, 1 acknowledged, -1 abandoned
	CreatedAt      time.Time
	AcknowledgedAt time.Time // zero if not acknowledged
}

// AcknowledgeOutbox marks the pending outbox row for a run as acknowledged. It
// is idempotent-failing: re-acknowledging an already-acknowledged row returns
// ErrOutboxNotFound.
func (s *Store) AcknowledgeOutbox(ctx context.Context, runID string) error {
	res, err := s.db.ExecContext(ctx,
		`UPDATE finalization_outbox SET acknowledged = 1, acknowledged_at = ?
		WHERE run_id = ? AND acknowledged = 0`,
		nowStamp(), runID)
	if err != nil {
		return err
	}
	if n, _ := res.RowsAffected(); n == 0 {
		return ErrOutboxNotFound
	}
	return nil
}

// AbandonOutbox marks a pending outbox row as abandoned (acknowledged = -1)
// when the supervisor is confirmed dead and identity is irrecoverably lost
// (ADR-0003 §2 step 3). The run stays terminal; the leak is recorded.
func (s *Store) AbandonOutbox(ctx context.Context, runID string, reason string) error {
	res, err := s.db.ExecContext(ctx,
		`UPDATE finalization_outbox SET acknowledged = -1, acknowledged_at = ?
		WHERE run_id = ? AND acknowledged = 0`,
		nowStamp(), runID)
	if err != nil {
		return err
	}
	if n, _ := res.RowsAffected(); n == 0 {
		return ErrOutboxNotFound
	}
	_ = reason
	return nil
}

// GetOutbox loads the outbox row for a run.
func (s *Store) GetOutbox(ctx context.Context, runID string) (OutboxRow, error) {
	row := s.db.QueryRowContext(ctx, `SELECT
		run_id, terminal_state, supervisor_pid, supervisor_pgid,
		socket_path, token, acknowledged, created_at, acknowledged_at
	FROM finalization_outbox WHERE run_id = ?`, runID)
	r, err := scanOutbox(row)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return OutboxRow{}, ErrOutboxNotFound
		}
		return OutboxRow{}, err
	}
	return r, nil
}

// ListPendingOutbox returns all outbox rows with acknowledged = 0. These are
// the terminal runs whose supervisor finalization is still owed; they must not
// be dropped from active processing.
func (s *Store) ListPendingOutbox(ctx context.Context) ([]OutboxRow, error) {
	rows, err := s.db.QueryContext(ctx, `SELECT
		run_id, terminal_state, supervisor_pid, supervisor_pgid,
		socket_path, token, acknowledged, created_at, acknowledged_at
	FROM finalization_outbox WHERE acknowledged = 0 ORDER BY created_at ASC`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []OutboxRow
	for rows.Next() {
		r, err := scanOutbox(rows)
		if err != nil {
			return nil, err
		}
		out = append(out, r)
	}
	return out, rows.Err()
}

func scanOutbox(row interface {
	Scan(dest ...any) error
}) (OutboxRow, error) {
	var (
		r       OutboxRow
		created string
		acked   sql.NullString
	)
	err := row.Scan(
		&r.RunID, &r.TerminalState, &r.SupervisorPID, &r.SupervisorPGID,
		&r.SocketPath, &r.Token, &r.Acknowledged, &created, &acked,
	)
	if err != nil {
		return OutboxRow{}, err
	}
	if r.CreatedAt, err = parseStamp(created); err != nil {
		return OutboxRow{}, fmt.Errorf("parse outbox created_at: %w", err)
	}
	if acked.Valid && acked.String != "" {
		if r.AcknowledgedAt, err = parseStamp(acked.String); err != nil {
			return OutboxRow{}, fmt.Errorf("parse outbox acknowledged_at: %w", err)
		}
	}
	return r, nil
}

// Package store is the durable SQLite journal for Ananke runs.
//
// It owns the cleanup state machine (ADR-0003) and the finalization outbox:
// terminal state transitions are committed in the same SQLite transaction as
// their outbox row, so a crash between commit and supervisor finalization can
// never lose the cleanup obligation.
package store

// State is a run's lifecycle state in the cleanup state machine (ADR-0003 §1).
type State string

const (
	// StateCreated: run record exists; worker not yet launched.
	StateCreated State = "created"
	// StateRunning: worker is executing; transcript streaming.
	StateRunning State = "running"
	// StateCancelling: cancellation requested; awaiting group quiescence.
	StateCancelling State = "cancelling"
	// StateCleanupRequired: error detected while the group was alive; cleanup
	// pending. Nonterminal.
	StateCleanupRequired State = "cleanup_required"
	// StateRecoveryUnknown: supervisor unreachable; identity ambiguous.
	// Nonterminal.
	StateRecoveryUnknown State = "recovery_unknown"
	// StateCompleted: trusted zero exit + full transcript + group quiescent.
	// Terminal.
	StateCompleted State = "completed"
	// StateFailed: nonzero exit or transcript error after authenticated
	// cleanup. Terminal.
	StateFailed State = "failed"
	// StateCancelled: group quiesced after a cancellation request. Terminal.
	StateCancelled State = "cancelled"
)

// Terminal reports whether the state is terminal (no outgoing transitions).
func (s State) Terminal() bool { return IsTerminal(s) }

// IsTerminal reports whether a state is terminal.
func IsTerminal(s State) bool {
	switch s {
	case StateCompleted, StateFailed, StateCancelled:
		return true
	}
	return false
}

// allowedTransitions is the adjacency table of the cleanup state machine.
// Terminal states have no outgoing edges. `created` may only advance to
// `running`. Self-loops are forbidden.
var allowedTransitions = map[State]map[State]struct{}{
	StateCreated: {StateRunning: {}},

	StateRunning: {
		StateCancelling:      {},
		StateCleanupRequired: {},
		StateRecoveryUnknown: {},
		StateCompleted:       {},
		StateFailed:          {},
		StateCancelled:       {},
	},

	StateCancelling: {
		StateCancelled:       {},
		StateRecoveryUnknown: {},
		StateCleanupRequired: {},
		StateRunning:         {},
	},

	StateCleanupRequired: {
		StateFailed:          {},
		StateCompleted:       {},
		StateCancelled:       {},
		StateRecoveryUnknown: {},
		StateRunning:         {},
	},

	StateRecoveryUnknown: {
		StateRunning:         {},
		StateCleanupRequired: {},
		StateCancelling:      {},
		StateCompleted:       {},
		StateFailed:          {},
		StateCancelled:       {},
	},
}

// CanTransition reports whether a state transition is permitted by the
// cleanup state machine. The store layer additionally enforces that a
// terminal transition commits an outbox row in the same transaction.
func CanTransition(from, to State) bool {
	if from == to {
		return false
	}
	targets, ok := allowedTransitions[from]
	if !ok {
		return false
	}
	_, ok = targets[to]
	return ok
}

