package store

import (
	"context"
	"database/sql"
	"errors"
	"fmt"
	"time"
)

// Event is a single journaled transcript event for a run.
type Event struct {
	RunID            string
	Seq              int64
	Type             string
	Payload          []byte
	TranscriptOffset int64
	WrittenAt        time.Time
}

// AppendEvent appends a transcript event to the journal with a per-run
// monotonic sequence number and commits the transcript offset atomically in
// the same transaction. The committed offset never rewinds: it advances to
// max(committed_offset, transcriptOffset).
func (s *Store) AppendEvent(ctx context.Context, runID, typ string, payload []byte, transcriptOffset int64) (Event, error) {
	if runID == "" {
		return Event{}, errors.New("run id required")
	}
	tx, err := s.db.BeginTx(ctx, nil)
	if err != nil {
		return Event{}, err
	}
	defer func() { _ = tx.Rollback() }()

	var maxSeq sql.NullInt64
	if err := tx.QueryRowContext(ctx,
		`SELECT MAX(seq) FROM events WHERE run_id = ?`, runID).Scan(&maxSeq); err != nil {
		return Event{}, fmt.Errorf("select max seq: %w", err)
	}
	nextSeq := int64(1)
	if maxSeq.Valid {
		nextSeq = maxSeq.Int64 + 1
	}
	now := nowStamp()
	if _, err := tx.ExecContext(ctx, `INSERT INTO events
		(run_id, seq, type, payload, transcript_offset, written_at)
		VALUES (?, ?, ?, ?, ?, ?)`,
		runID, nextSeq, typ, string(payload), transcriptOffset, now); err != nil {
		return Event{}, fmt.Errorf("insert event: %w", err)
	}
	// Atomic offset commit: the durable high-water mark advances with the
	// event row in this transaction and never moves backwards.
	res, err := tx.ExecContext(ctx,
		`UPDATE runs SET committed_offset = MAX(committed_offset, ?), updated_at = ? WHERE id = ?`,
		transcriptOffset, now, runID)
	if err != nil {
		return Event{}, fmt.Errorf("update committed offset: %w", err)
	}
	if n, _ := res.RowsAffected(); n == 0 {
		return Event{}, ErrRunNotFound
	}
	if err := tx.Commit(); err != nil {
		return Event{}, err
	}
	writtenAt, _ := time.Parse(time.RFC3339Nano, now)
	return Event{
		RunID:            runID,
		Seq:              nextSeq,
		Type:             typ,
		Payload:          payload,
		TranscriptOffset: transcriptOffset,
		WrittenAt:        writtenAt,
	}, nil
}

// CommittedOffset returns the durable transcript high-water mark for a run.
func (s *Store) CommittedOffset(ctx context.Context, runID string) (int64, error) {
	var off int64
	err := s.db.QueryRowContext(ctx,
		`SELECT committed_offset FROM runs WHERE id = ?`, runID).Scan(&off)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return 0, ErrRunNotFound
		}
		return 0, err
	}
	return off, nil
}

// ListEvents returns all events for a run with sequence strictly greater than
// afterSeq, ordered by ascending sequence. Pass afterSeq=0 to read from the
// start. This is the reconnectable read path: a reader persists its last
// consumed sequence and resumes without loss or duplication after a crash.
func (s *Store) ListEvents(ctx context.Context, runID string, afterSeq int64) ([]Event, error) {
	rows, err := s.db.QueryContext(ctx, `SELECT
		run_id, seq, type, payload, transcript_offset, written_at
	FROM events WHERE run_id = ? AND seq > ? ORDER BY seq ASC`, runID, afterSeq)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []Event
	for rows.Next() {
		var (
			e         Event
			payload   string
			writtenAt string
		)
		if err := rows.Scan(&e.RunID, &e.Seq, &e.Type, &payload, &e.TranscriptOffset, &writtenAt); err != nil {
			return nil, err
		}
		e.Payload = []byte(payload)
		if e.WrittenAt, err = time.Parse(time.RFC3339Nano, writtenAt); err != nil {
			return nil, fmt.Errorf("parse written_at: %w", err)
		}
		out = append(out, e)
	}
	return out, rows.Err()
}

// HighestEventSeq returns the highest committed event sequence for a run, or 0
// if the run has no events.
func (s *Store) HighestEventSeq(ctx context.Context, runID string) (int64, error) {
	var seq sql.NullInt64
	err := s.db.QueryRowContext(ctx,
		`SELECT MAX(seq) FROM events WHERE run_id = ?`, runID).Scan(&seq)
	if err != nil {
		return 0, err
	}
	if !seq.Valid {
		return 0, nil
	}
	return seq.Int64, nil
}

package store

import (
	"context"
	"database/sql"
	"encoding/json"
	"errors"
	"fmt"
	"time"
)

// ErrRunNotFound is returned when a run id does not exist.
var ErrRunNotFound = errors.New("run not found")

// ErrProjectNotFound is returned when a project id does not exist.
var ErrProjectNotFound = errors.New("project not found")

// ErrWorkstreamNotFound is returned when a workstream id does not exist.
var ErrWorkstreamNotFound = errors.New("workstream not found")

// RunSpec is the immutable launch configuration recorded at run creation.
type RunSpec struct {
	WorkerPath     string
	WorkerArgs     []string
	WorkerEnv      []string
	TranscriptPath string
	SocketPath     string
	Token          string
	IdentityPath   string
}

// Run is a run row projected from the journal.
type Run struct {
	ID              string
	ProjectID       string
	WorkstreamID    string
	State           State
	WorkerPath      string
	WorkerArgs      []string
	WorkerEnv       []string
	TranscriptPath  string
	SocketPath      string
	Token           string
	IdentityPath    string
	SupervisorPID   int
	SupervisorPGID  int
	WorkerPID       int
	CommittedOffset int64
	CreatedAt       time.Time
	UpdatedAt       time.Time
}

// CreateProject inserts a project row.
func (s *Store) CreateProject(ctx context.Context, id, name, root string) error {
	_, err := s.db.ExecContext(ctx,
		`INSERT INTO projects (id, name, root, created_at) VALUES (?, ?, ?, ?)`,
		id, name, root, nowStamp())
	return err
}

// CreateWorkstream inserts a workstream row under an existing project.
func (s *Store) CreateWorkstream(ctx context.Context, id, projectID, name string) error {
	_, err := s.db.ExecContext(ctx,
		`INSERT INTO workstreams (id, project_id, name, created_at) VALUES (?, ?, ?, ?)`,
		id, projectID, name, nowStamp())
	if err != nil {
		return fmt.Errorf("create workstream: %w", err)
	}
	return nil
}

// CreateRun inserts a run row in the `created` state and records the initial
// state transition (seq 0) in the journal.
func (s *Store) CreateRun(ctx context.Context, id, projectID, workstreamID string, spec RunSpec) error {
	if id == "" {
		return errors.New("run id required")
	}
	if spec.WorkerPath == "" {
		return errors.New("worker path required")
	}
	now := nowStamp()
	args, err := json.Marshal(spec.WorkerArgs)
	if err != nil {
		return fmt.Errorf("marshal worker args: %w", err)
	}
	env, err := json.Marshal(spec.WorkerEnv)
	if err != nil {
		return fmt.Errorf("marshal worker env: %w", err)
	}
	tx, err := s.db.BeginTx(ctx, nil)
	if err != nil {
		return err
	}
	defer func() { _ = tx.Rollback() }()

	if _, err := tx.ExecContext(ctx, `INSERT INTO runs (
		id, project_id, workstream_id, state,
		worker_path, worker_args, worker_env,
		transcript_path, socket_path, token, identity_path,
		supervisor_pid, supervisor_pgid, worker_pid, committed_offset,
		created_at, updated_at
	) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`,
		id, projectID, workstreamID, StateCreated,
		spec.WorkerPath, string(args), string(env),
		spec.TranscriptPath, spec.SocketPath, spec.Token, spec.IdentityPath,
		0, 0, 0, 0, now, now,
	); err != nil {
		return fmt.Errorf("insert run: %w", err)
	}
	if _, err := tx.ExecContext(ctx, `INSERT INTO state_transitions
		(run_id, seq, from_state, to_state, reason, written_at)
		VALUES (?, 0, '', ?, 'created', ?)`,
		id, StateCreated, now); err != nil {
		return fmt.Errorf("insert initial transition: %w", err)
	}
	return tx.Commit()
}

// GetRun loads a single run by id.
func (s *Store) GetRun(ctx context.Context, id string) (Run, error) {
	row := s.db.QueryRowContext(ctx, `SELECT
		id, project_id, workstream_id, state,
		worker_path, worker_args, worker_env,
		transcript_path, socket_path, token, identity_path,
		supervisor_pid, supervisor_pgid, worker_pid, committed_offset,
		created_at, updated_at
	FROM runs WHERE id = ?`, id)
	r, err := scanRun(row)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return Run{}, ErrRunNotFound
		}
		return Run{}, err
	}
	return r, nil
}

// scanRun decodes a run row from a single-row scanner.
func scanRun(row interface {
	Scan(dest ...any) error
}) (Run, error) {
	var (
		r         Run
		argsJSON  string
		envJSON   string
		createdAt string
		updatedAt string
	)
	err := row.Scan(
		&r.ID, &r.ProjectID, &r.WorkstreamID, &r.State,
		&r.WorkerPath, &argsJSON, &envJSON,
		&r.TranscriptPath, &r.SocketPath, &r.Token, &r.IdentityPath,
		&r.SupervisorPID, &r.SupervisorPGID, &r.WorkerPID, &r.CommittedOffset,
		&createdAt, &updatedAt,
	)
	if err != nil {
		return Run{}, err
	}
	if err := json.Unmarshal([]byte(argsJSON), &r.WorkerArgs); err != nil {
		return Run{}, fmt.Errorf("unmarshal worker args: %w", err)
	}
	if err := json.Unmarshal([]byte(envJSON), &r.WorkerEnv); err != nil {
		return Run{}, fmt.Errorf("unmarshal worker env: %w", err)
	}
	if r.CreatedAt, err = time.Parse(time.RFC3339Nano, createdAt); err != nil {
		return Run{}, fmt.Errorf("parse created_at: %w", err)
	}
	if r.UpdatedAt, err = time.Parse(time.RFC3339Nano, updatedAt); err != nil {
		return Run{}, fmt.Errorf("parse updated_at: %w", err)
	}
	return r, nil
}

package store

import (
	"context"
	"fmt"
)

// terminalStateValues is the SQL-level enumeration of terminal states, kept in
// sync with IsTerminal. SQLite has no function form of IsTerminal, so the
// active-runs query enumerates them.
var terminalStateValues = []string{
	string(StateCompleted),
	string(StateFailed),
	string(StateCancelled),
}

// ListActiveRuns returns every non-terminal run PLUS every terminal run whose
// finalization outbox row is still pending (acknowledged = 0). A terminal run
// is never silently dropped from recovery until its outbox row is
// acknowledged (ADR-0003 §2 invariant 4).
func (s *Store) ListActiveRuns(ctx context.Context) ([]Run, error) {
	q := `SELECT
		id, project_id, workstream_id, state,
		worker_path, worker_args, worker_env,
		transcript_path, socket_path, token, identity_path,
		supervisor_pid, supervisor_pgid, worker_pid, committed_offset,
		created_at, updated_at
	FROM runs r
	WHERE r.state NOT IN ('completed','failed','cancelled')
	   OR EXISTS (
		SELECT 1 FROM finalization_outbox o
		WHERE o.run_id = r.id AND o.acknowledged = 0
	   )
	ORDER BY r.created_at ASC`
	rows, err := s.db.QueryContext(ctx, q)
	if err != nil {
		return nil, fmt.Errorf("list active runs: %w", err)
	}
	defer rows.Close()
	var out []Run
	for rows.Next() {
		r, err := scanRun(rows)
		if err != nil {
			return nil, err
		}
		out = append(out, r)
	}
	return out, rows.Err()
}

// ListRunsByProject returns all runs under a project, ordered by creation.
func (s *Store) ListRunsByProject(ctx context.Context, projectID string) ([]Run, error) {
	q := `SELECT
		id, project_id, workstream_id, state,
		worker_path, worker_args, worker_env,
		transcript_path, socket_path, token, identity_path,
		supervisor_pid, supervisor_pgid, worker_pid, committed_offset,
		created_at, updated_at
	FROM runs WHERE project_id = ? ORDER BY created_at ASC`
	rows, err := s.db.QueryContext(ctx, q, projectID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var out []Run
	for rows.Next() {
		r, err := scanRun(rows)
		if err != nil {
			return nil, err
		}
		out = append(out, r)
	}
	return out, rows.Err()
}

// SetRunSupervisor records the supervisor identity (pid/pgid) and worker pid on
// the run row, used by the daemon after it has launched the supervisor and
// read the identity file.
func (s *Store) SetRunSupervisor(ctx context.Context, runID string, supervisorPID, supervisorPGID, workerPID int) error {
	res, err := s.db.ExecContext(ctx,
		`UPDATE runs SET supervisor_pid = ?, supervisor_pgid = ?, worker_pid = ?, updated_at = ? WHERE id = ?`,
		supervisorPID, supervisorPGID, workerPID, nowStamp(), runID)
	if err != nil {
		return err
	}
	if n, _ := res.RowsAffected(); n == 0 {
		return ErrRunNotFound
	}
	return nil
}

