		_, _ = cmd.Process.Wait()
	}()
	waitForSocket(t, socketPath, 5*time.Second)

	resp := sendCmd(t, socketPath, "test-token", "adopt")
	if resp["ok"] != true {
		t.Fatalf("adopt failed: %v", resp)
	}
	if resp["state"] != "running" {
		t.Errorf("state = %v, want running", resp["state"])
	}
}

