// forkSupervisor re-executes the test binary as a supervisor helper. Returns the
// cmd, the socket path (for client connections), and the result-file path.
func forkSupervisor(t *testing.T, storePath, runID string, env supEnv) (*exec.Cmd, string, string) {
	t.Helper()
	dir := t.TempDir()
	if env.IdentityPath == "" {
		env.IdentityPath = filepath.Join(dir, "identity.json")
	}
	if env.SocketPath == "" {
		env.SocketPath = filepath.Join(dir, "supervisor.sock")
	}
