		"ANANKE_SUP_SOCKET=" + env.SocketPath,
		"ANANKE_SUP_TOKEN=" + env.Token,
		"ANANKE_SUP_RESULT=" + resultPath,
		"ANANKE_SUP_GRACE_MS=" + strconv.Itoa(env.GraceMS),
	}
