	args = append(args, "ANANKE_FW_EVENTS="+strconv.Itoa(env.FWEvents))
	args = append(args, "ANANKE_FW_EXIT="+strconv.Itoa(env.FWExit))
	args = append(args, "ANANKE_FW_DELAY_MS="+strconv.Itoa(env.FWDelayMS))
