	st, _ := store.Open(storePath)
	defer st.Close()
	r := waitUntilState(t, st, "run-5", store.StateCancelled, 10*time.Second)
	// WorkerPID should be recorded.
	if r.WorkerPID == 0 {
		t.Errorf("worker pid not recorded")
