	var childPID int
	deadline := time.Now().Add(3 * time.Second)
	for time.Now().Before(deadline) {
		if data, err := os.ReadFile(childPIDFile); err == nil {
			if n, e := atoi(string(data)); e == nil && n > 0 {
				childPID = n
				break
			}
		}
		time.Sleep(20 * time.Millisecond)
	}
	if childPID == 0 {
		t.Fatalf("child PID file not written within 3s")
	}

	// Read identity to get the supervisor's PID for liveness checks.
	id := readIdentityFile(t, filepath.Join(filepath.Dir(socketPath), "identity.json"))

