		}
		// Check via kill(0).
		if !processAlive(childPID) {
			break
		}
		time.Sleep(100 * time.Millisecond)
	}
	if processAlive(childPID) {
		t.Errorf("resistant child PID %d still alive after supervisor exit", childPID)
	}
	_ = id
}

